features.snippet:
module sub (
    input clk,
    input [7:0] sub_non_top,
    output [7:0] sub_top_out,
    output [7:0] sub_non_top_out
);  /*verilator hier_block*/
  assign sub_top_out = 8'(clk) ^ $c1(2);
  assign sub_non_top_out = sub_non_top ^ $c1(3);
endmodule

logic [7:0] non_top_input = $c1(2);
logic [7:0] top_out = 0;
logic [7:0] non_top_out = 0;
sub sub (
    .clk(clk),
    .sub_non_top(non_top_input),
    .sub_top_out(top_out),
    .sub_non_top_out(non_top_out)
);
